using System.Text.Json;
using System.Text.Json.Serialization;

var builder = WebApplication.CreateBuilder(args);

// Add services
builder.Services.AddHttpClient();
builder.Services.AddOpenApi();

var app = builder.Build();

// Configure the HTTP request pipeline
if (app.Environment.IsDevelopment())
{
    app.UseSwagger();
    app.UseSwaggerUI();
    app.MapOpenApi();
}

app.UseHttpsRedirection();

// Endpoints
app.MapGet("/dashboard", async (HttpClient httpClient) =>
{
    try
    {
        var response = await httpClient.GetAsync("http://localhost:5002/dashboard-data");
        var content = await response.Content.ReadAsStringAsync();

        using JsonDocument doc = JsonDocument.Parse(content);
        var root = doc.RootElement;

        // Parse user data
        var user = JsonSerializer.Deserialize<JsonElement>(root.GetProperty("user").GetRawText());
        var userName = user.GetProperty("name").GetString();
        var userEmail = user.GetProperty("email").GetString();

        // Parse orders
        var orders = JsonSerializer.Deserialize<List<Order>>(root.GetProperty("orders").GetRawText());
        var totalOrders = orders?.Count ?? 0;
        var lastOrders = orders?.OrderByDescending(o => o.Id).Take(2).ToList() ?? new();

        // Parse products
        var products = JsonSerializer.Deserialize<List<Product>>(root.GetProperty("products").GetRawText()) ?? new();

        // Build response
        var dashboard = new
        {
            name = userName,
            email = userEmail,
            totalOrders,
            lastOrders = lastOrders.Select(o => new
            {
                o.Id,
                o.UserId,
                o.ProductId,
                o.Total
            }).ToList(),
            highlights = products.Select(p => new
            {
                p.Id,
                p.Name,
                p.Price
            }).ToList()
        };

        return Results.Ok(dashboard);
    }
    catch (Exception ex)
    {
        return Results.BadRequest(new { error = ex.Message });
    }
})
.WithName("GetDashboard")
.WithOpenApi();

app.Run();

record Order
{
    [JsonPropertyName("id")]
    public int Id { get; set; }

    [JsonPropertyName("userId")]
    public int UserId { get; set; }

    [JsonPropertyName("productId")]
    public int ProductId { get; set; }

    [JsonPropertyName("total")]
    public decimal Total { get; set; }
}

record Product
{
    [JsonPropertyName("id")]
    public int Id { get; set; }

    [JsonPropertyName("name")]
    public string Name { get; set; }

    [JsonPropertyName("price")]
    public decimal Price { get; set; }
}

